# ── a random Work identity generator. Every string that a rule is FORBIDDEN to key on is randomized,
#    so a passing fuzz run proves the refusal is keyed on typed structure, not on any subject literal. ──
_PREFIX = ['10.1056', '10.2307', '10.1086', '10.5555', '10.1001', '10.48550', '10.3386', '10.1093']
_WORDS = ('Widget Gadget Protocol Doctrine Kernel Estimator Cohort Statute Transformer Sepsis Estoppel '
          'Wage Attention Trial Regimen Liability Mobility Inference Synthesis Foreseeability').split()


def _rand_domain(rng):
    """A V-shaped domain dict with every identifier/subject string independently randomized."""
    def doi():
        return f'{rng.choice(_PREFIX)}/{rng.choice(_WORDS).lower()}-{rng.randrange(10**6):06d}'

    def name():
        return rng.choice(_WORDS)

    def title():
        return ' '.join(rng.sample(_WORDS, 5))
    a1, a2 = name(), name()
    b1, b2 = name(), name()
    return dict(
        id=f'rand{rng.randrange(10**9)}', doi=doi(), foreign_doi=doi(),
        title=title(), authors=(a1, a2), byline=f'By {a1} {a2}',
        venue=' '.join(rng.sample(_WORDS, 3)) + ' Review',
        foreign_title=title(), foreign_byline=f'By {b1} {b2}',
        generic_title=rng.choice(_WORDS) + ' Report')
